if typing.TYPE_CHECKING:  # pragma: no cover
    from hashlib import _Hash


class Auth:
    """
    Base class for all authentication schemes.

    To implement a custom authentication scheme, subclass `Auth` and override
    the `.auth_flow()` method.

    If the authentication scheme does I/O such as disk access or network calls, or uses
    synchronization primitives such as locks, you should override `.sync_auth_flow()`
    and/or `.async_auth_flow()` instead of `.auth_flow()` to provide specialized
    implementations that will be used by `Client` and `AsyncClient` respectively.
    """

    requires_request_body = False
    requires_response_body = False

    def auth_flow(self, request: Request) -> typing.Generator[Request, Response, None]:
        """
        Execute the authentication flow.

        To dispatch a request, `yield` it:

        '''
        yield request
        '''

        The client will `.send()` the response back into the flow generator. You can
        access it like so:

        '''
        response = yield request
        '''

        A `return` (or reaching the end of the generator) will result in the
        client returning the last response obtained from the server.

        You can dispatch as many requests as is necessary.
        """
        yield request

    def sync_auth_flow(
        self, request: Request
    ) -> typing.Generator[Request, Response, None]:
        """
        Execute the authentication flow synchronously.

        By default, this defers to `.auth_flow()`. You should override this method
        when the authentication scheme does I/O and/or uses concurrency primitives.
        """
        if self.requires_request_body:
            request.read()

        flow = self.auth_flow(request)
        request = next(flow)

        while True:
            response = yield request
            if self.requires_response_body:
                response.read()

            try:
                request = flow.send(response)
            except StopIteration:
                break

    async def async_auth_flow(
        self, request: Request
    ) -> typing.AsyncGenerator[Request, Response]:
        """
        Execute the authentication flow asynchronously.

        By default, this defers to `.auth_flow()`. You should override this method
        when the authentication scheme does I/O and/or uses concurrency primitives.
        """
        if self.requires_request_body:
            await request.aread()

        flow = self.auth_flow(request)
        request = next(flow)

        while True:
            response = yield request
            if self.requires_response_body:
                await response.aread()

            try:
                request = flow.send(response)
            except StopIteration:
                break


class FunctionAuth(Auth):
    """
    Allows the 'auth' argument to be passed as a simple callable function,
    that takes the request, and returns a new, modified request.
    """

    def __init__(self, func: typing.Callable[[Request], Request]) -> None:
        """
        Initialize a FunctionAuth instance.

        Args:
            func: A callable that accepts a Request and returns a modified Request.
        """
        self._func = func

    def auth_flow(self, request: Request) -> typing.Generator[Request, Response, None]:
        """
        Execute the authentication flow by calling the provided function.

        The function should return a Request instance. This request is yielded
        to be sent by the client.
        """
        yield self._func(request)


class BasicAuth(Auth):
    """
    Allows the 'auth' argument to be passed as a (username, password) pair,
    and uses HTTP Basic authentication.
    """

    def __init__(
        self, username: typing.Union[str, bytes], password: typing.Union[str, bytes]
    ) -> None:
        """
        Initialize BasicAuth with the provided credentials.

        Args:
            username: Username as str or bytes.
            password: Password as str or bytes.
        """
        self._auth_header = self._build_auth_header(username, password)

    def auth_flow(self, request: Request) -> typing.Generator[Request, Response, None]:
        """
        Add the Authorization header to the request and yield it.

        This generator yields the request with the Basic Authorization header applied.
        """
        request.headers["Authorization"] = self._auth_header
        yield request

    @staticmethod
    def _build_auth_header(
        username: typing.Union[str, bytes], password: typing.Union[str, bytes]
    ) -> str:
        """
        Build the HTTP Basic Authorization header value from username and password.

        This returns a string of the form 'Basic <base64-credentials>'.

        Args:
            username: Username as str or bytes.
            password: Password as str or bytes.

        Returns:
            The Authorization header value.
        """
        if isinstance(username, str):
            username = username.encode("utf-8")
        if isinstance(password, str):
            password = password.encode("utf-8")
        credentials = b"%b:%b" % (username, password)
        b64 = b64encode(credentials).decode("ascii")
        return f"Basic {b64}"


class DigestAuth(Auth):
    """
    Implements HTTP Digest Access Authentication (RFC 2617/RFC 7616).

    This implementation provides a minimal, compatible digest auth flow:
    - It performs an initial unauthenticated request and, upon receiving a 401
      with a Digest challenge, computes the appropriate Authorization header and
      resends the request.
    """

    def __init__(
        self, username: typing.Union[str, bytes], password: typing.Union[str, bytes]
    ) -> None:
        """
        Initialize DigestAuth with username and password.

        Args:
            username: The username as str or bytes.
            password: The password as str or bytes.
        """
        if isinstance(username, str):
            username = username.encode("utf-8")
        if isinstance(password, str):
            password = password.encode("utf-8")
        self.username = username
        self.password = password
        self._nonce_count = 0

    def auth_flow(self, request: Request) -> typing.Generator[Request, Response, None]:
        """
        The auth flow for Digest authentication.

        Yields the initial request, inspects the 401 response for a Digest challenge,
        and if present computes the response and re-sends the request with an
        Authorization header.
        """
        # Send initial request.
        response = yield request

        if response.status_code == 401:
            www_authenticate = response.headers.get("WWW-Authenticate", "")
            # Find digest challenge
            if "digest" in www_authenticate.lower():
                challenge = _get_header_value(www_authenticate, "Digest") or www_authenticate
                challenge = challenge.strip()
                # Parse challenge parameters
                realm = _get_header_value(challenge, "realm")
                nonce = _get_header_value(challenge, "nonce")
                algorithm = _get_header_value(challenge, "algorithm") or "MD5"
                opaque = _get_header_value(challenge, "opaque")
                qop_value = _get_header_value(challenge, "qop")
                qop = _resolve_qop(qop_value)

                # Build authorization header
                self._nonce_count += 1
                nc_value = f"{self._nonce_count:08x}"
                cnonce = _get_client_nonce()
                uri = request.url.path or "/"
                method = request.method

                response_digest = digest(
                    username=self.username,
                    password=self.password,
                    method=method,
                    uri=uri,
                    realm=realm,
                    nonce=nonce,
                    nc=nc_value,
                    cnonce=cnonce,
                    qop=qop,
                    algorithm=algorithm,
                    opaque=opaque,
                    body=b"",
                )

                # Build Authorization header string
                auth_values = [
                    f'username="{to_str(self.username)}"',
                    f'realm="{realm}"' if realm is not None else "",
                    f'nonce="{nonce}"' if nonce is not None else "",
                    f'uri="{uri}"',
                    f'response="{response_digest}"',
                ]
                if opaque:
                    auth_values.append(f'opaque="{opaque}"')
                if algorithm:
                    auth_values.append(f'algorithm={algorithm}')
                if qop:
                    auth_values.append(f'qop={qop}')
                    auth_values.append(f'nc={nc_value}')
                    auth_values.append(f'cnonce="{cnonce}"')

                auth_header = "Digest " + ", ".join([v for v in auth_values if v])

                request.headers["Authorization"] = auth_header
                # Re-send the request with the Authorization header.
                response = yield request

        return response

    @staticmethod
    def _build_auth_header(*args, **kwargs) -> str:
        """
        Placeholder for compatibility: builds auth header for DigestAuth.

        This method is present for API compatibility; use `auth_flow` which
        computes and sets the Authorization header on the request instead.
        """
        raise NotImplementedError("DigestAuth builds headers dynamically in auth_flow.")


def digest(
    username: bytes,
    password: bytes,
    method: str,
    uri: str,
    realm: typing.Optional[str],
    nonce: str,
    nc: str,
    cnonce: str,
    qop: typing.Optional[str],
    algorithm: str = "MD5",
    opaque: typing.Optional[str] = None,
    body: bytes = b"",
) -> str:
    """
    Compute the HTTP Digest authentication response hash.

    Implements the digest calculation per RFC 2617 (MD5) and supports qop
    of 'auth' and legacy (no qop). Other algorithms are not implemented.

    Args:
        username: Username as bytes.
        password: Password as bytes.
        method: HTTP method (e.g., 'GET').
        uri: Request URI.
        realm: Authentication realm.
        nonce: Server-specified nonce.
        nc: Hex count of the nonce used (8 hex digits).
        cnonce: Client nonce.
        qop: Quality of protection (e.g., 'auth' or 'auth-int').
        algorithm: Hash algorithm (only 'MD5' supported here).
        opaque: Opaque value from server (ignored in digest calc).
        body: Request body as bytes (used for auth-int if implemented).

    Returns:
        The hexadecimal string of the response digest.
    """
    if algorithm and algorithm.upper() != "MD5":
        raise ProtocolError(f"Unsupported digest algorithm: {algorithm}")

    # HA1 = MD5(username:realm:password)
    a1 = b"%b:%b:%b" % (username, realm.encode("utf-8") if realm else b"", password)
    ha1 = hashlib.md5(a1).hexdigest()

    # HA2 depends on qop
    if qop == "auth-int":
        # HA2 = MD5(method:uri:MD5(entity-body))
        entity_hash = hashlib.md5(body).hexdigest()
        a2 = f"{method}:{uri}:{entity_hash}".encode("utf-8")
    else:
        # HA2 = MD5(method:uri)
        a2 = f"{method}:{uri}".encode("utf-8")
    ha2 = hashlib.md5(a2).hexdigest()

    if qop:
        response_hash_source = f"{ha1}:{nonce}:{nc}:{cnonce}:{qop}:{ha2}"
    else:
        response_hash_source = f"{ha1}:{nonce}:{ha2}"

    response_digest = hashlib.md5(response_hash_source.encode("utf-8")).hexdigest()
    return response_digest


def _get_client_nonce() -> str:
    """
    Generate a client nonce value for Digest authentication.

    Returns:
        A hex-encoded nonce suitable for use as cnonce.
    """
    return hashlib.md5(os.urandom(8)).hexdigest()


def _get_header_value(header: str, key: str) -> typing.Optional[str]:
    """
    Extract a named parameter value from a WWW-Authenticate or Digest header.

    The function looks for key="value" or key=value segments and returns the
    unquoted string value if found, otherwise None.

    Args:
        header: The header string to parse.
        key: The parameter name to extract.

    Returns:
        The parameter value as string, or None if not present.
    """
    # Normalize: look for key=... with optional quotes.
    pattern = re.compile(rf'{re.escape(key)}\s*=\s*("([^"]*)"|([^\s,]+))', flags=re.IGNORECASE)
    match = pattern.search(header)
    if not match:
        return None
    value = match.group(2) if match.group(2) is not None else match.group(3)
    if value is None:
        return None
    return unquote(value)


def _resolve_qop(qop_value: typing.Optional[str]) -> typing.Optional[str]:
    """
    Determine which qop value to use from the server-provided qop directive.

    Prefers 'auth' if present, then 'auth-int'. If multiple values are provided,
    the best available option is returned. If qop_value is None, returns None.

    Args:
        qop_value: The raw qop directive string from the server (comma-separated).

    Returns:
        The chosen qop token (e.g., 'auth'), or None if no qop is to be used.
    """
    if not qop_value:
        return None
    # Parse comma-separated list
    tokens = [t.strip().strip('"').lower() for t in parse_http_list(qop_value)]
    if "auth" in tokens:
        return "auth"
    if "auth-int" in tokens:
        return "auth-int"
    # Otherwise return the first token
    return tokens[0] if tokens else None